def simulate_load_balancer(n, events):
    from collections import deque
    queues = [deque() for _ in range(n)]
    loads = [0] * n
    request_id = 0
    peak_load = 0

    for event in events:
        if event[0] == "request":
            a, b = event[1], event[2]
            if loads[a] < loads[b]:
                target = a
            elif loads[b] < loads[a]:
                target = b
            else:
                target = min(a, b)
            queues[target].append(request_id)
            loads[target] += 1
            request_id += 1
            if loads[target] > peak_load:
                peak_load = loads[target]
        elif event[0] == "complete":
            s = event[1]
            if queues[s]:
                queues[s].popleft()
                loads[s] -= 1

    return (loads, peak_load)
